/**
 * kb-data.js
 * Base de conocimiento en base64.
 * Total casos: 260
 */

(function () {
  var raw = "";

  try {
    window.KB_TEXT = decodeURIComponent(escape(atob(raw)));
    window.KB_COUNT = 260;
  } catch (e) {
    console.error('Error al decodificar la KB:', e);
    window.KB_TEXT = '';
    window.KB_COUNT = 0;
  }
})();
